import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const AdGrid = ({ pageNumber = 1 }) => {
  const [squares, setSquares] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const navigate = useNavigate();

  // 🎯 CRITICAL FIX: Calculate correct square numbers for each page
  const startSquare = (pageNumber - 1) * 200 + 1;
  const endSquare = pageNumber * 200;

  console.log(`📄 Page ${pageNumber}: Loading squares ${startSquare} to ${endSquare}`);

  useEffect(() => {
    const initializeSquares = () => {
      setIsLoading(true);
      
      // 🎯 FIXED: Create mock purchases for ALL 2000 squares across 10 pages
      const createMockPurchases = () => {
        const mockPurchases = {};
        const totalSquares = 2000; // 10 pages × 200 squares
        
        console.log(`🔄 Creating mock data for ${totalSquares} squares across 10 pages...`);
        
        for (let squareNum = 1; squareNum <= totalSquares; squareNum++) {
          // Occupy every 10th square for testing (200 occupied squares total)
          if (squareNum % 10 === 0) {
            const page = Math.ceil(squareNum / 200);
            mockPurchases[squareNum] = {
              status: 'active',
              businessName: `Business ${squareNum}`,
              logoData: '/logo.PNG',
              adText: `Special Deal #${squareNum}`,
              dealLink: `https://business${squareNum}.com/deal`,
              endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
              page: page
            };
          }
        }
        
        console.log(`✅ Created ${Object.keys(mockPurchases).length} mock purchases`);
        return mockPurchases;
      };

      // Load or create purchases
      let purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
      
      if (Object.keys(purchases).length === 0) {
        console.log('📦 No existing purchases found. Creating mock data...');
        purchases = createMockPurchases();
        localStorage.setItem('squarePurchases', JSON.stringify(purchases));
      } else {
        console.log(`📦 Found ${Object.keys(purchases).length} existing purchases`);
      }

      // 🎯 FIXED: Create ONLY 200 squares for the CURRENT page
      const squaresForThisPage = Array.from({ length: 200 }, (_, index) => {
        const squareNumber = startSquare + index; // This gives 1-200, 201-400, 401-600, etc.
        const purchase = purchases[squareNumber];
        
        console.log(`🔍 Square ${squareNumber}:`, purchase ? 'OCCUPIED' : 'AVAILABLE');
        
        if (purchase && purchase.status === 'active') {
          const endDate = new Date(purchase.endDate);
          const today = new Date();
          
          if (today < endDate) {
            return {
              id: squareNumber,
              isAvailable: false,
              businessName: purchase.businessName,
              logoData: purchase.logoData,
              adText: purchase.adText,
              dealLink: purchase.dealLink,
              endDate: purchase.endDate,
              page: purchase.page
            };
          }
        }
        
        // Available square
        return {
          id: squareNumber,
          isAvailable: true,
          price: '£1/day'
        };
      });

      console.log(`🎯 Page ${pageNumber}: Created ${squaresForThisPage.length} squares`);
      console.log(`🎯 Occupied squares: ${squaresForThisPage.filter(sq => !sq.isAvailable).length}`);
      console.log(`🎯 Available squares: ${squaresForThisPage.filter(sq => sq.isAvailable).length}`);
      
      setSquares(squaresForThisPage);
      setIsLoading(false);
    };

    initializeSquares();
  }, [pageNumber, startSquare]);

  const handleSquareClick = (square) => {
    if (square.isAvailable) {
      navigate('/purchase', { 
        state: { 
          squareNumber: square.id,
          pageNumber: pageNumber 
        } 
      });
    } else {
      window.open(square.dealLink, '_blank');
    }
  };

  // Loading state
  if (isLoading) {
    return (
      <div className="grid-container">
        <div className="page-info">
          <h3>Page {pageNumber} - Loading Squares {startSquare} to {endSquare}...</h3>
        </div>
        <div className="squares-grid loading-squares">
          {Array.from({ length: 200 }).map((_, i) => (
            <div key={i} className="loading-square"></div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="grid-container">
      <div className="page-info">
        <h3>Page {pageNumber} - Squares {startSquare} to {endSquare}</h3>
        <p>
          {squares.filter(square => !square.isAvailable).length}/200 squares occupied
        </p>
        <div className="shuffle-indicator">
          ✅ All 200 squares loaded for this page
        </div>
      </div>
      
      <div className="squares-grid">
        {squares.map(square => (
          <div
            key={square.id}
            className={`square ${square.isAvailable ? '' : 'occupied'}`}
            onClick={() => handleSquareClick(square)}
            title={!square.isAvailable ? 
              `${square.businessName}\nClick to visit deal` : 
              `Square #${square.id}\nClick to purchase - £1 per day`
            }
          >
            {square.isAvailable ? (
              <>
                <div className="square-text">BUY THIS SQUARE</div>
                <div className="square-price">£1/day</div>
                <div className="square-number">#{square.id}</div>
              </>
            ) : (
              <>
                <img 
                  src={square.logoData || '/logo.PNG'} 
                  alt={square.businessName} 
                  className="occupied-logo" 
                />
                <div className="square-number">#{square.id}</div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdGrid;
